import{p as t,bh as r,I as a,U as o}from"./chunks/framework.BpabEsSf.js";const m=JSON.parse('{"title":"Быстрый старт","description":"","frontmatter":{"title":"Быстрый старт","date":"2025-05-01T23:00:00.000Z","permalink":"/guide/quickstart","categories":["Guide"],"tags":["Guide"],"top":true,"sticky":1},"headers":[],"relativePath":"ru/01.Guide/01.Introduction/10.Quick Start.md","filePath":"ru/01.Guide/01.Introduction/10.Quick Start.md","lastUpdated":null}'),i={name:"ru/01.Guide/01.Introduction/10.Quick Start.md"};function n(d,e,s,l,c,u){return r(),a("div",null,[...e[0]||(e[0]=[o('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /ru\\01.Guide\\01.Introduction\\10.Quick Start.md for this page in Markdown format</div><h1 id="быстрыи-старт" tabindex="-1">Быстрый старт <a class="header-anchor" href="#быстрыи-старт" aria-label="Permalink to &quot;Быстрый старт&quot;">​</a></h1><h3 id="быстрая-установка" tabindex="-1">Быстрая установка <a class="header-anchor" href="#быстрая-установка" aria-label="Permalink to &quot;Быстрая установка&quot;">​</a></h3><h4 id="android" tabindex="-1">Android: <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android:&quot;">​</a></h4><ol><li>Загрузите последнюю сборку APK-пакета со страницы официальных релизов <strong><a href="https://github.com/JoyinJoester/Monica/releases" target="_blank" rel="noreferrer">Releases</a></strong>.</li><li>Установите пакет на любое устройство под управлением <strong>Android 8.0+</strong> и настройте свой Мастер-пароль при первом запуске.</li></ol><h4 id="расширение-для-браузера-chrome-edge" tabindex="-1">Расширение для браузера (Chrome / Edge): <a class="header-anchor" href="#расширение-для-браузера-chrome-edge" aria-label="Permalink to &quot;Расширение для браузера (Chrome / Edge):&quot;">​</a></h4><ol><li>Перейдите в локальный каталог проекта <code>Monica for Browser</code> для сборки ресурсов расширения.</li><li>Откройте страницу <code>chrome://extensions/</code> в вашем браузере и активируйте <strong>«Режим разработчика»</strong> в правом верхнем углу.</li><li>Нажмите кнопку <strong>«Загрузить распакованное расширение»</strong> и выберите сгенерированную папку дистрибутива <code>dist</code>.</li></ol><hr><h3 id="известные-ограничения" tabindex="-1">Известные ограничения <a class="header-anchor" href="#известные-ограничения" aria-label="Permalink to &quot;Известные ограничения&quot;">​</a></h3><ul><li>Из-за индивидуальных особенностей конфигурации и ограничений совместимости на системном уровне, Monica for Android в настоящее время не может инициализировать или генерировать ключи доступа <strong>Passkey</strong> на некоторых устройствах под управлением операционной системы <strong>Xiaomi HyperOS</strong>.</li></ul>',10)])])}const _=t(i,[["render",n]]);export{m as __pageData,_ as default};
